func getSellValue(inv character.Inventory) int {
	if baseItem, ok := store.Items[inv.ItemID]; ok {
		return int(baseItem.Price)
	}
	return inv.Price
}

func getRarityClass(rarity string) string {
	switch rarity {
	case "common":
		return "badge-ghost"
	case "uncommon":
		return "badge-info text-info-content"
	case "rare":
		return "badge-primary"
	case "epic":
		return "badge-secondary"
	case "legendary":
		return "badge-accent"
	default:
		return "badge-ghost"
	}
}

